"use strict";jQuery.Class("Settings_Recruitment_Workflows_Js",{},{buildWorkflowPopoverContent:function(t){if(!t||!t.length)return"";return'<ul class="list-unstyled mb-0">'+t.map(function(t){const e=jQuery("<div>").text(t.summary||"").html();return'<li><a href="'+(t.editUrl||"#")+'">'+e+"</a></li>"}).join("")+"</ul>"},registerWorkflowPopovers:function(){const t=jQuery("#recruitmentWorkflowsContainer"),e=this;t.find(".js-workflow-badge").each(function(){const t=jQuery(this);let r=[];try{r=JSON.parse(t.attr("data-workflows")||"[]")}catch(t){r=[]}t.popover({html:!0,trigger:"focus",placement:"auto",container:"body",title:app.vtranslate("LBL_WORKFLOW_POPOVER_TITLE","Settings:Recruitment"),content:e.buildWorkflowPopoverContent(r)})}),t.on("click",".js-workflow-badge",function(t){t.preventDefault(),jQuery(this).focus()})},registerEvents:function(){this.registerWorkflowPopovers()}}),jQuery(document).ready(function(){(new Settings_Recruitment_Workflows_Js).registerEvents()});